    59→    /// Returns `true` if the poll is a [`Poll::Ready`] value.
    60→    ///
    61→    /// # Examples
    62→    ///
    63→    /// ```
    64→    /// # use core::task::Poll;
    65→    /// let x: Poll<u32> = Poll::Ready(2);
    66→    /// assert_eq!(x.is_ready(), true);
    67→    ///
    68→    /// let x: Poll<u32> = Poll::Pending;
