    93→    #[rustc_const_stable(feature = "const_poll", since = "1.49.0")]
    94→    #[stable(feature = "futures_api", since = "1.36.0")]
    95→    pub const fn is_pending(&self) -> bool {
    96→        !self.is_ready()
    97→    }
    98→}
