   218→#[rustc_const_unstable(feature = "const_convert", issue = "143773")]
   219→impl<T> const From<T> for Poll<T> {
   220→    /// Moves the value into a [`Poll::Ready`] to make a `Poll<T>`.
   221→    ///
   222→    /// # Example
   223→    ///
   224→    /// ```
   225→    /// # use core::task::Poll;
